function SearchResults({ query }: { query: string }) {
  const [retries, setRetries] = useState(0);

  useEffect(() => {
    if (retries < 3) {
      fetchResults(query).catch(() => {
        setTimeout(() => setRetries((r) => r + 1), 1000);
      });
    }
  }, [query, retries]);

